import React, { useRef, useEffect } from 'react';

function Graph({ results, currentR, onCanvasClick }) {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      drawArea(canvas, currentR, results);
    }
  }, [currentR, results]);

  const handleClick = (e) => {
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    // Конвертация в координаты графика
    const graphX = parseFloat(((x - 200) / 40).toFixed(3));
    const graphY = parseFloat(((200 - y) / 40).toFixed(3));

    onCanvasClick(graphX, graphY);
  };

  const drawArea = (canvas, r, points) => {
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, 400, 400);

    // Оси
    drawAxes(ctx);

    // Область
    if (r > 0) {
      drawShapes(ctx, r);
    }

    // Точки
    points.forEach(point => {
      if (point.r === r) {
        drawPoint(ctx, point.x, point.y, point.hit);
      }
    });
  };

  const drawAxes = (ctx) => {
    ctx.strokeStyle = '#2c3e50';
    ctx.lineWidth = 2;

    // Ось X
    ctx.beginPath();
    ctx.moveTo(0, 200);
    ctx.lineTo(400, 200);
    ctx.stroke();

    // Ось Y
    ctx.beginPath();
    ctx.moveTo(200, 0);
    ctx.lineTo(200, 400);
    ctx.stroke();

    // Стрелки и разметка
    // ... (ваш код из canvas.js)
  };

  const drawShapes = (ctx, r) => {
    ctx.fillStyle = 'rgba(52, 152, 219, 0.3)';
    ctx.strokeStyle = '#3498db';

    // Четверть круга
    ctx.beginPath();
    ctx.arc(200, 200, r * 40, -Math.PI/2, 0, false);
    ctx.lineTo(200, 200);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();

    // Треугольник
    ctx.beginPath();
    ctx.moveTo(200, 200);
    ctx.lineTo(200 - r * 40, 200);
    ctx.lineTo(200, 200 + r * 40);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();

    // Прямоугольник
    ctx.beginPath();
    ctx.rect(200, 200, r * 40, r * 20);
    ctx.fill();
    ctx.stroke();
  };

  const drawPoint = (ctx, x, y, hit) => {
    const pointX = 200 + x * 40;
    const pointY = 200 - y * 40;

    ctx.beginPath();
    ctx.arc(pointX, pointY, 4, 0, Math.PI * 2);
    ctx.fillStyle = hit ? '#27ae60' : '#e74c3c';
    ctx.fill();
    ctx.strokeStyle = '#2c3e50';
    ctx.stroke();
  };

  return (
    <div className="graph-container">
      <h3>Область проверки (R = {currentR})</h3>
      <canvas
        ref={canvasRef}
        width="400"
        height="400"
        onClick={handleClick}
        className="area-canvas"
      />
      <p className="graph-hint">Кликните на график для выбора точки</p>
    </div>
  );
}

export default Graph;
